mapper.select:
select
from counselor_schedule cs left join counselor c on cs.counselor_id = c.id left join sys_user su on c.user_id = su.id left join appointment a on cs.id = a.schedule_id
and cs.counselor_id = #{counselorId}
and cs.status = #{status}
and cs.schedule_date = #{scheduleDate}
group by cs.id, cs.counselor_id, su.name, cs.schedule_date, cs.start_time, cs.end_time, cs.status, cs.remark, cs.create_time, cs.update_time order by cs.schedule_date desc, cs.start_time asc, cs.id desc

select count(*)
from counselor_schedule
where counselor_id = #{counselorId}
  and schedule_date = #{scheduleDate}
  and start_time < #{endTime}
  and end_time > #{startTime}

    and id != #{id}

select count(*)
from appointment
where schedule_id = #{scheduleId}
